js.home:
const cate = env.get("category") || '/tw/new';
const page = Number(env.get("page")||1);
let url = cate;
if(page>1){ url = `${cate}?page=${page}`; }
const fullUrl = `${env.baseUrl}${url}`;
const resp = await req(fullUrl,{headers:{'User-Agent':'Mozilla/5.0','Referer':env.baseUrl},timeout:30000});
const html = resp.content || resp;
const $ = kitty.load(html);
let items = [];
$('div.item').each((i,el)=>{
 const link = $(el).find('a.poster').attr('href');
 if(!link) return;
 const id = link.replace(env.baseUrl,'');
 const title = $(el).find('a.title').text().trim();
 const cover = $(el).find('img').attr('src') || '';
 const remark = $(el).find('.duration').text().trim();
 if(id && title){ items.push({id,title,cover,remark}); }
});
return items.slice(0,12);

