js.home:
const cate = env.get("category")  'undefined';
const page = Number(env.get("page")||0);

if(cate === 'home'){
 const fullUrl = `${env.baseUrl}/home`;
 const resp = await req(fullUrl,{headers:{'User-Agent':'Mozilla/5.0'},timeout:60000});
 const html = resp.content  resp;
 if(!html) return [];
 const $ = kitty.load(html);
 const modules = [];
 const allItems = [];
 const seen = new Set();

 $('a[href^="/books/"]').each((i,el)=>{
 const id = $(el).attr('href');
 if(seen.has(id)) return; // 去重
 seen.add(id);
 const title = $(el).find('div.truncate').text().trim();
 let coverStyle = $(el).find('div[style]').attr('style')  '';
 let coverMatch = coverStyle.match(/https:\/\/r5\.rmcdn10\.xyz\/(.+?\.jpg)/);
 const cover = coverMatch ? `https://r5.rmcdn10.xyz/${coverMatch[1]}` : '';
 const desc = $(el).find('div.text-muted-foreground').first().text().trim();
 const remark = $(el).find('div.text-muted-foreground.text-sm').text().trim();
 if(id && title){ allItems.push({id,title,cover,desc,remark}); }
 });

 const titles = ['超高人氣','今日爆款','最近更新','本週熱門','完結精選'];
 for(let g=0; g<5; g++){
 const group = allItems.slice(g*12,(g+1)*12);
 if(group.length){
 const bannerItems = group.slice(0,8);
 const listItems = group.slice(8,12);
 if(bannerItems.length) modules.push({type:'banner',title:titles[g],videos:bannerItems});
 if(listItems.length) modules.push({type:'list',title:titles[g],videos:listItems});
 }
 }

 return {type:'complex',data:modules};
} else {
 let url = `/books?continued=${cate}&page=${page}`;
 const fullUrl = `${env.baseUrl}${url}`;
 const resp = await req(fullUrl,{headers:{'User-Agent':'Mozilla/5.0'},timeout:60000});
 const html = resp.content  resp;
 const $ = kitty.load(html);
 let items = [];
 const seen = new Set();
 $('a[href^="/books/"]').each((i,el)=>{
 const id = $(el).attr('href');
 if(seen.has(id)) return;
 seen.add(id);
 const title = $(el).find('div.truncate').text().trim();
 let coverStyle = $(el).find('div[style]').attr('style')  '';
 let coverMatch = coverStyle.match(/https:\/\/r5\.rmcdn10\.xyz\/(.+?\.jpg)/);
 const cover = coverMatch ? `https://r5.rmcdn10.xyz/${coverMatch[1]}` : '';
 const desc = $(el).find('div.text-muted-foreground').first().text().trim();
 const remark = $(el).find('div.text-muted-foreground.text-sm').text().trim();
 if(id && title){ items.push({id,title,cover,desc,remark}); }
 });
 return items;
}

