js.detail:
const id = env.get("movieId")  '';
const cover = env.get("cover")  '';
const url = ${env.baseUrl}${id};
const headers = { 'User-Agent': 'Mozilla/5.0', 'Referer': env.baseUrl };
const resp = await req(url, { headers, timeout: 20000 });
const html = typeof resp === 'string' ? resp : (resp && resp.content ? resp.content : '');
if(!html) return {};
const $ = kitty.load(html);
const title = $('h1').text().trim()  $('title').text().trim()  '';
const desc = $('meta[name="description"]').attr('content') || '';
let playUrl = '';
$('script[type="text/javascript"]').each((i,el)=>{
  const txt = $(el).html();
  if(txt && txt.includes('player_aaaa')){
    const match = txt.match(/\"url\":\"([^\"]+)\"/);
    if(match){ playUrl = match[1].replace(/\\\//g,'/'); }
  }
});
const playlist = playUrl ? [{ title: '在线播放', videos: [ { text: '播放', id: playUrl, type: 'direct' } ] }] : [];
return { id, title, cover, desc, playlist };
